import { AutkSpatialDb } from 'autk-db';

const _origFetch = globalThis.fetch;
globalThis.fetch = (url, opts = {}) => {
    if (typeof url === 'string' && url.includes('overpass-api.de')) {
        opts = { ...opts, headers: { ...opts.headers, 'User-Agent': 'autk-db/1.3.1' } };
    }
    return _origFetch(url, opts);
};

const db = new AutkSpatialDb();
await db.init();

await db.loadOsm({
    queryArea: {
        geocodeArea: 'Chicago',
        areas: ['Loop'],
    },
    outputTableName: 'table_osm',
    autoLoadLayers: {
        coordinateFormat: 'EPSG:3395',
        layers: ['surface', 'parks', 'water'],
        dropOsmTable: true,
    },
});

const layers = [];
for (const layer of db.getLayerTables()) {
    layers.push({
        name: layer.name,
        type: layer.type,
        geojson: await db.getLayer(layer.name),
    });
}
return layers;

// 'arg' is the layer array from the upstream JS Computation node:
// [{ name: string, type: string, geojson: GeoJSON.FeatureCollection }, ...]
// 'canvas' is the canvas element rendered inside this node.
// 'AutkMap' is imported from autk-map automatically.
const map = new AutkMap(canvas);
await map.init();
for (const layer of arg) {
    map.loadCollection(layer.name, { collection: layer.geojson, type: layer.type });
}
map.draw();
